class Solution:
    def possibleStringCount(self, word, k):
        MOD = 10 ** 9 + 7
        n = len(word)
        runs = []
        i = 0
        while i < n:
            j = i
            while j < n and word[j] == word[i]:
                j += 1
            runs.append(j - i)
            i = j
        cap = k
        dp = [0] * (cap + 1)
        dp[0] = 1
        for g in runs:
            new_dp = [0] * (cap + 1)
            for total, ways in enumerate(dp):
                if ways == 0:
                    continue
                for length in range(1, g + 1):
                    nt = min(total + length, cap)
                    new_dp[nt] = (new_dp[nt] + ways) % MOD
            dp = new_dp
        return sum(dp[k:]) % MOD if k <= cap else 0

