var possibleStringCount = function(word, k) {
    const MOD = 1000000007n;
    const n = word.length;
    const runs = [];
    let i = 0;
    while (i < n) {
        let j = i;
        while (j < n && word[j] === word[i]) j++;
        runs.push(j - i);
        i = j;
    }
    const m = runs.length;
    let product = 1n;
    for (const g of runs) product = (product * BigInt(g)) % MOD;
    if (m >= k) return Number(product);
    const target = k - m;
    let dp = new Array(target).fill(0n);
    dp[0] = 1n;
    for (const g of runs) {
        const prefix = new Array(target + 1).fill(0n);
        for (let idx = 0; idx < target; idx++) {
            prefix[idx + 1] = (prefix[idx] + dp[idx]) % MOD;
        }
        const newDp = new Array(target).fill(0n);
        for (let e = 0; e < target; e++) {
            const lo = Math.max(0, e - (g - 1));
            newDp[e] = ((prefix[e + 1] - prefix[lo]) % MOD + MOD) % MOD;
        }
        dp = newDp;
    }
    let invalid = 0n;
    for (const v of dp) invalid = (invalid + v) % MOD;
    return Number(((product - invalid) % MOD + MOD) % MOD);
};
